settings.cellContentFunction:
let duration = alarm.endTs - alarm.startTs;
let durationStr = 'N/A';
if (duration > 0) {
    durationStr = ctx.milliSecondsToTimeString.transform(duration, true);
    let durationParts = durationStr.split(' ');
    if (durationParts.length > 2) {
        durationParts.splice(2 - durationParts.length);
        durationStr = durationParts.join(' ');
    }
}

return '<button id="al-duration" class="mdc-button mat-mdc-button mat-unthemed mat-mdc-button-base al-cell-button">' +
            '<span class="mdc-button__label">'+durationStr+'</span>' +
            '<span class="mat-mdc-button-persistent-ripple mdc-button__ripple"></span>' +
        '</button>';

var severityText = '';
var severityImage = '';
switch (value) {
    case 'CRITICAL':
        severityText = 'Critical alarm';
        severityImage = 'data:image/svg+xml;base64,';
        break;
    case 'MAJOR':
        severityText = 'Major alarm';
        severityImage = 'data:image/svg+xml;base64,';
        break;
    case 'WARNING':
        severityText = 'Warning alarm';
        break;
    case 'MINOR':
        severityText = 'Minor alarm';
        break;
}

if (severityText) {
    return '<div style="width: 100%; height: 100%; display: flex; justify-content: center; align-items: center;"><img style="cursor: pointer; width: 15px; height: 15px;" src="' + severityImage + '"' +
            'onmouseover="$(this).hasClass(\'tooltipstered\') ? $(this).tooltipster(\'show\') : ($(this).tooltipster({theme: \'tooltipster-tb\', speed: 0, delay: 0, arrow: false, content: \''+severityText+'\'}) && $(this).tooltipster(\'show\'));"/>' + 
           '</div>';
} else {
    return '';
}

rowClick.customFunction:
let $injector = widgetContext.$scope.$injector;
let assetService = $injector.get(widgetContext.servicesMap.get('assetService'));
let utils = $injector.get(widgetContext.servicesMap.get('utils'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));

let alarm = additionalParams.alarm;
let targetEntityId = alarm.entityId;
let target = $event.target;
if (target.tagName !== 'BUTTON') {
    target = $(target).parents('button')[0];
}
if (target) {
    let id = target.id;
    if (id) {
        let popoverTrigger;
        let stateParams;
        switch (id) {
            case 'al-location':
                popoverTrigger = getPopoverTrigger(target);
                findLocationData(alarm.entityId).subscribe(
                    (locationData) => {
                        if (locationData) {
                            const room = locationData.room;
                            const locationLastUpdateTs = locationData.locationAttribute.lastUpdateTs;
                            stateParams = utils.deepClone(widgetContext.stateController.getStateParams());
                            stateParams.entityId = room.id;
                            stateParams.entityName = room.name;
                            stateParams.locationLastUpdateTs = locationLastUpdateTs;
                            openStateInPopover(popoverTrigger, 'room_location_details', stateParams, 'bottomLeft', '500px', '400px');
                        }
                    }
                );
                break;
            case 'al-duration':    
                popoverTrigger = getPopoverTrigger(target);
                stateParams = utils.deepClone(widgetContext.stateController.getStateParams());
                stateParams.alarm = alarm;
                openStateInPopover(popoverTrigger, 'alarm_duration', stateParams, 'bottomLeft', '250px', '120px');
                break;
            case 'al-resident': 
                popoverTrigger = getPopoverTrigger(target);
                stateParams = utils.deepClone(widgetContext.stateController.getStateParams());
                stateParams.entityId = alarm.entityId;
                stateParams.entityName = alarm.Name;
                openStateInPopover(popoverTrigger, 'resident_brief', stateParams, 'bottomLeft', '300px', '260px');
                break;
            case 'al-emergency':
                getCustomerAttribute('emergencyPhoneNumber').subscribe(
                    (emergencyPhoneNumber) => {
                        if (emergencyPhoneNumber) {
                            window.open('tel:' + emergencyPhoneNumber, '_self');
                        }
                    }
                );
                break;
            case 'al-phone':
                getCustomerAttribute('nursePhoneNumber').subscribe(
                    (nursePhoneNumber) => {
                        if (nursePhoneNumber) {
                            window.open('tel:' + nursePhoneNumber, '_self');
                        }
                    }
                );
                break;
        }
    }
}

function openStateInPopover(popoverTrigger, stateId, stateParams, preferredPlacement, width, height) {
    widgetContext.actionsApi.openDashboardStateInPopover({target: popoverTrigger}, stateId, stateParams, true, preferredPlacement, true, width, height);
}

function getPopoverTrigger(target) {
    let id = target.id;
    let triggerId = id + '-trigger-'+alarm.id.id;
    let parentTable = $(target).parents('.table-container');
    let popoverTrigger = $('#'+triggerId, parentTable);
    if (!popoverTrigger.length) {
        let parentRow = $(target).parents('mat-row');
        let top = parentRow.position().top + $(target).position().top + parentTable.scrollTop();
        let left = $(target).position().left;
        let width = $(target).width();
        let height = $(target).height();
        popoverTrigger = $('<div id="'+triggerId+'" style="width: '+width+'px; height: '+height+'px; position: absolute; top: '+top+'px; left: '+left+'px; pointer-events: none;"></div>');
        parentTable.append(popoverTrigger);
    }
    return popoverTrigger[0];
}

function findLocationData(entityId) {
    return getLocationAttribute(entityId).pipe(
        widgetContext.rxjs.switchMap((locationAttribute) => {
            if (locationAttribute) {
                const roomName = locationAttribute.value;
                return assetService.getUserAssets(widgetContext.pageLink(10, 0, roomName), 'AL_Room').pipe(
                    widgetContext.rxjs.map((pageData) => {
                        let found =  pageData.data.filter((asset) => asset.name === roomName);
                        if (found.length) {
                            return {room: found[0], locationAttribute: locationAttribute};
                        } else {
                            return null;
                        }
                    })
                );
            } else {
                return widgetContext.rxjs.of(null);
            }
        })
    );
}

function getLocationAttribute(entityId) {
    return attributeService.getEntityAttributes(entityId, 'SERVER_SCOPE', ['currentRoom']).pipe(
        widgetContext.rxjs.map((attributes) => {
            if (attributes.length) {
                return attributes[0];
            } else {
                return null;
            }
        })
    );
}

function getCustomerAttribute(key) {
    return getCustomerId().pipe(
        widgetContext.rxjs.switchMap((customerId) => {
            return attributeService.getEntityAttributes(customerId, 'SERVER_SCOPE', [key]).pipe(
                widgetContext.rxjs.map((attributes) => {
                    if (attributes.length && attributes[0].key === key) {
                        return attributes[0].value;
                    } else {
                        return null;
                    }
                })
            );
        })
    );
}

function getCustomerId() {
    const customerAliasId = widgetContext.aliasController.getEntityAliasId('Customer');
    return widgetContext.aliasController.getAliasInfo(customerAliasId).pipe(
        widgetContext.rxjs.map((info) => {
          return {id: info.currentEntity.id, entityType: info.currentEntity.entityType};  
        })
    );
}

